final:
module RefModule(
    input           clk,
    input           rst,
    input           serial_in,
    output  reg [3:0] reg_out
);
  wire _tap_clk = clk & {1{1'b1}};


always @(posedge clk or posedge rst) begin
    if (rst)
        reg_out <= 4'b0000;
    else
        reg_out <= {reg_out[2:0], serial_in};
end

endmodule
